<div class="grid grid-2"><div class="card"><h3>Overtime Request</h3><form method="post" action="<?=url('/overtime/store')?>"><?=csrf_field()?><label>Employee</label><select name="employee_id"><?php foreach($employees as $e1):?><option value="<?=e($e1['id'])?>"><?=e($e1['full_name'])?></option><?php endforeach;?></select><label>Date</label><input name="overtime_date" type="date" required><div class="form-row"><div><label>Start</label><input name="start_time" type="time" required></div><div><label>End</label><input name="end_time" type="time" required></div></div><label>Reason</label><textarea name="reason"></textarea><button class="btn btn-primary">Submit</button></form></div><div class="card"><h3>Requests</h3><table class="table"><tr><th>Employee</th><th>Date</th><th>Hours</th><th>Status</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['overtime_date'])?></td><td><?=e($r['total_hours'])?></td><td><span class="badge badge-info"><?=e($r['status'])?></span></td></tr><?php endforeach;?></table></div></div>
